As we know, `m_visited`  is initialized with `init_visited()` that will called by `simplifier::initialize()`
~~~~
    void simplifier::init_visited() {
        m_visited.reset();
        m_visited.resize(2*s.num_vars(), false);
    }
    void simplifier::initialize() {
        m_need_cleanup = false;
        s.m_cleaner(true);
        m_last_sub_trail_sz = s.m_trail.size();
        m_use_list.init(s.num_vars());
        m_sub_todo.reset();
        m_sub_bin_todo.reset();
        m_elim_todo.reset();
        init_visited();
        TRACE("after_cleanup", s.display(tout););
        CASSERT("sat_solver", s.check_invariant());
    }
~~~~

While executing `simplifier::operator()`,  

- `initialize()`  initailizes `m_visited` a the begining of `simplifier::operator()`
-  About 10 lines of code below,  `init_visited()` initializes `m_visited` again

~~~~
    void simplifier::operator()(bool learned) {
        if (s.inconsistent())
            return;
        if (!m_subsumption && !m_elim_blocked_clauses && !m_resolution)
            return;

        initialize();                                                       // m_visited is initialized 

        CASSERT("sat_solver", s.check_invariant());
        TRACE("before_simplifier", s.display(tout););

        m_sub_todo.reset();
        m_sub_bin_todo.reset();
        s.m_cleaner(true);
        m_last_sub_trail_sz = s.m_trail.size();
        TRACE("after_cleanup", s.display(tout););
        CASSERT("sat_solver", s.check_invariant());
        m_need_cleanup = false;
        m_use_list.init(s.num_vars());
        init_visited();                                            // m_visited is initialized here again. 
        m_learned_in_use_lists = false;

~~~~

